public inline fun <A, B, C> Either<A, B>.flatMap(f: (right: B) -> Either<A, C>): Either<A, C> {
  contract {
    callsInPlace(f, InvocationKind.AT_MOST_ONCE)
    (this@flatMap is Right) holdsIn f
  }
  return when (this) {
    is Right -> f(this.value)
    is Left -> this
  }
}

public inline fun <A, B, C> Either<A, B>.handleErrorWith(f: (A) -> Either<C, B>): Either<C, B> {
  contract {
    callsInPlace(f, InvocationKind.AT_MOST_ONCE)
    (this@handleErrorWith is Left) holdsIn f
  }
  return when (this) {
    is Left -> f(this.value)
    is Right -> this
  }
}

public inline infix fun <A, B> Either<A, B>.getOrElse(default: (A) -> B): B {
  contract {
    callsInPlace(default, InvocationKind.AT_MOST_ONCE)
    (this@getOrElse is Left) holdsIn default
  }
  return when (this) {
    is Left -> default(this.value)
    is Right -> this.value
  }
}

public fun Route.path(format: RoutePathFormat = RoutePathFormat.Default): String {
    val parentPath = parent?.path(format)
    val pathComponent = selector as? RoutePathComponent ?: return parentPath.orEmpty()
    val formattedPath = format.format(pathComponent)
    return when {
        parentPath == null -> formattedPath
        formattedPath.isEmpty() -> parentPath
        parentPath.endsWith('/') || formattedPath.startsWith('/') -> "$parentPath$formattedPath"
        else -> "$parentPath/$formattedPath"
    }
}

internal fun Any?.toJsonElement(): JsonElement = when (this) {
  is Map<*, *> -> JsonObject(this.asMap.mapValues { it.value.toJsonElement() })
  is List<*> -> JsonArray(map { it.toJsonElement() })
  is Boolean -> JsonPrimitive(this)
  is Number -> JsonPrimitive(this)
  is String -> JsonPrimitive(this)
  null -> JsonNull
  else -> error("cannot convert $this to JsonElement")
}

public inline fun <T> Option<T>.getOrElse(default: () -> T): T {
  contract {
    callsInPlace(default, InvocationKind.AT_MOST_ONCE)
    (this@getOrElse is None) holdsIn default
  }
  return when (this) {
    is Some -> value
    else -> default()
  }
}

public inline fun <A> Option<A>.recover(recover: SingletonRaise<None>.() -> A): Option<A> {
  contract {
    callsInPlace(recover, InvocationKind.AT_MOST_ONCE)
    (this@recover is None) holdsIn recover
  }
  return when (this@recover) {
    is None -> option { recover() }
    is Some -> this@recover
  }
}

