    DataChannel.State.OPEN -> WebRtc.DataChannel.State.OPEN
    DataChannel.State.CLOSING -> WebRtc.DataChannel.State.CLOSING
    DataChannel.State.CLOSED -> WebRtc.DataChannel.State.CLOSED
}

internal fun JsonElement.toAny(): Any? = when (this) {
  is JsonObject -> this.mapValues { it.value.toAny() }
  is JsonArray -> this.map { it.toAny() }
  is JsonPrimitive -> {
    when {
      isString -> this.content
      this is JsonNull -> null
      else -> booleanOrNull ?: intOrNull ?: longOrNull ?: doubleOrNull ?: error("cannot decode $this")
    }
  }
  else -> error("cannot convert $this to Any")
}

private fun List<IrModelGroup>.walk(depth: Int, atDepth: Int, excludeNames: Set<String>): List<IrModelGroup> {
  return if (depth == atDepth) {
    flatten(excludeNames)
  } else {
    map { modelGroup ->
      modelGroup.walk(depth, atDepth, excludeNames)
    }
  }
}

internal fun ComponentRegistry.Builder.addCommonComponents(): ComponentRegistry.Builder {
    return this
        // Mappers
        .add(StringMapper())
        .add(PathMapper())
        // Keyers
        .add(FileUriKeyer())
        .add(UriKeyer())
        // Fetchers
        .add(FileUriFetcher.Factory())
        .add(ByteArrayFetcher.Factory())
        .add(DataUriFetcher.Factory())
        .add(BitmapFetcher.Factory())
}

fun close() = KoinPlatformTools.synchronized(this) {
    _koin.logger.debug("|- (-) Scope - id:'$id'")

    _callbacks.forEach { it.onScopeClose(this) }
    _callbacks.clear()
    _closed = true

    sourceValue = null

    _parameterStack?.get()?.clear()
    _parameterStack = null

    _koin.scopeRegistry.deleteScope(this)
}

protected inline fun stdObjectFunctions(
self: Any,
method: MethodDescription,
args: List<Any?>,
otherwise: () -> Any?,
): Any? =
when {
    method.isToString() -> toStr()
    method.isHashCode() -> InternalPlatformDsl.identityHashCode(self)
    method.isEquals() -> self === args[0]
    else -> otherwise()
}

internal inline fun ByteString.commonHex(): String {
  val result = CharArray(data.size * 2)
  var c = 0
  for (b in data) {
    result[c++] = HEX_DIGIT_CHARS[b shr 4 and 0xf]
    result[c++] = HEX_DIGIT_CHARS[b       and 0xf] // ktlint-disable no-multi-spaces
  }
  return result.concatToString()
}

@Suppress("NOTHING_TO_INLINE")
internal inline fun ByteString.commonEquals(other: Any?): Boolean {
  return when {
    other === this -> true
    other is ByteString -> other.size == data.size && other.rangeEquals(0, data, 0, data.size)
    else -> false
  }
}

