private fun List<Any>.startsWith(responsePath: List<Any>): Boolean {
  // start at 1 to drop the `data.`
  for (i in 1.until(responsePath.size)) {
    if (i - 1 >= this.size) {
      return false
    }
    if (responsePath[i] != this[i - 1]) {
      return false
    }
  }
  return true
}

private fun kindOf(nativeTrack: RTCMediaStreamTrack): WebRtcMedia.TrackType {
    return when (nativeTrack.kind()) {
        "audio" -> WebRtcMedia.TrackType.AUDIO
        "video" -> WebRtcMedia.TrackType.VIDEO
        else -> error("Unknown media track kind: ${nativeTrack.kind()}")
    }
}

internal fun WebRtc.SessionDescription.toIos(): RTCSessionDescription {
    return RTCSessionDescription(
        type = when (type) {
            WebRtc.SessionDescriptionType.OFFER -> RTCSdpType.RTCSdpTypeOffer
            WebRtc.SessionDescriptionType.ANSWER -> RTCSdpType.RTCSdpTypeAnswer
            WebRtc.SessionDescriptionType.PROVISIONAL_ANSWER -> RTCSdpType.RTCSdpTypePrAnswer
            WebRtc.SessionDescriptionType.ROLLBACK -> RTCSdpType.RTCSdpTypeRollback
        },
        sdp = sdp
    )
}
